#!/usr/bin/env python3
from __future__ import annotations

import shutil
import subprocess
import sys
from datetime import datetime
from pathlib import Path


REPO_NAME = "rapportini-arte-in-ferro"
EXPECTED_BRANCH = "nuovo-gestionale-windows"
WINDOWS_ROOT = Path("apps/windows/ArteInFerro.Rapportini.Desktop")


def is_repo(path: Path) -> bool:
    return (
        (path / ".git").exists()
        and (path / WINDOWS_ROOT / "ArteInFerro.Rapportini.Desktop.csproj").exists()
    )


def find_repo() -> Path:
    script_dir = Path(__file__).resolve().parent
    candidates: list[Path] = []

    for start in (Path.cwd(), script_dir):
        current = start.resolve()
        candidates.append(current)
        candidates.extend(current.parents)

    home = Path.home()
    candidates.extend([
        home / "Documents" / "GitHub" / REPO_NAME,
        home / "GitHub" / REPO_NAME,
        home / "Desktop" / REPO_NAME,
        home / "source" / "repos" / REPO_NAME,
    ])

    seen: set[Path] = set()
    for candidate in candidates:
        candidate = candidate.resolve()
        if candidate in seen:
            continue
        seen.add(candidate)
        if is_repo(candidate):
            return candidate

    for base in (home / "Documents", home / "Desktop"):
        if not base.exists():
            continue
        try:
            for candidate in base.glob(f"**/{REPO_NAME}"):
                if is_repo(candidate):
                    return candidate.resolve()
        except OSError:
            pass

    raise RuntimeError(
        "Repository non trovato. Apri GitHub Desktop, scegli il repository "
        "'rapportini-arte-in-ferro' e riprova."
    )


def current_branch(repo: Path) -> str:
    try:
        result = subprocess.run(
            ["git", "-C", str(repo), "rev-parse", "--abbrev-ref", "HEAD"],
            check=True,
            capture_output=True,
            text=True,
        )
        return result.stdout.strip()
    except Exception:
        head = (repo / ".git" / "HEAD").read_text(encoding="utf-8").strip()
        prefix = "ref: refs/heads/"
        return head[len(prefix):] if head.startswith(prefix) else head


def write_utf8(path: Path, content: str) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content.replace("\r\n", "\n"), encoding="utf-8", newline="\n")


def main() -> int:
    try:
        repo = find_repo()
        branch = current_branch(repo)
        print(f"Repository: {repo}")
        print(f"Ramo attuale: {branch}")

        if branch != EXPECTED_BRANCH:
            raise RuntimeError(
                f"Ramo non corretto. Seleziona '{EXPECTED_BRANCH}' in GitHub Desktop "
                f"prima di applicare il pacchetto. Ramo attuale: '{branch}'."
            )

        timestamp = datetime.now().strftime("%Y%m%d-%H%M%S")
        backup = Path.home() / "Desktop" / f"Backup-Gestionale-ArteInFerro-{timestamp}"
        backup.mkdir(parents=True, exist_ok=True)

        files = {
            repo / WINDOWS_ROOT / "App.xaml": APP_XAML,
            repo / WINDOWS_ROOT / "App.xaml.cs": APP_CS,
            repo / WINDOWS_ROOT / "Views" / "MainShellWindow.xaml": SHELL_XAML,
            repo / WINDOWS_ROOT / "Views" / "MainShellWindow.xaml.cs": SHELL_CS,
        }

        for path in files:
            if path.exists():
                relative = path.relative_to(repo)
                destination = backup / relative
                destination.parent.mkdir(parents=True, exist_ok=True)
                shutil.copy2(path, destination)

        for path, content in files.items():
            write_utf8(path, content)
            print(f"OK: {path.relative_to(repo)}")

        print()
        print("ARCHITETTURA GESTIONALE FASE 1 APPLICATA.")
        print("Android, iPhone e Supabase non sono stati modificati.")
        print(f"Backup locale: {backup}")
        print("Torna su GitHub Desktop e controlla i 4 file modificati.")
        return 0
    except Exception as exc:
        print()
        print(f"ERRORE: {exc}")
        return 1


